"""
MKT Christ — Luke chapters 19–20 (94 missing verses; 19:10 already present)
Output: data/commentary/mkt-christ/luke.json
Run: python3 scripts/zc-christ-luke-19-20.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH19_20 = {
"19": {
"1": "<p>Jesus entering Jericho (eiserchomai — he was passing through) positions him at the last stop before Jerusalem. Jericho was a wealthy priestly city; it is also the city Joshua conquered first when Israel entered the Promised Land (Josh 6). The second Joshua (whose Hebrew name Jesus shares) passes through Jericho on the way to the city of David to accomplish a greater conquest: not with trumpets and falling walls but with a cross and an empty tomb. Jericho frames the Zacchaeus encounter geographically as a 'first conquest' moment for the new Joshua's entry into the land.</p>",
"2": "<p>'Zacchaeus' (from Hebrew zakkay — 'pure/innocent') is a name whose meaning is ironically contradicted by his vocation: the pure man is the chief tax collector (architelōnēs — the only use of this title in the NT), the man others would call most impure. The irony is Christological: the one whose name means 'pure' is found by the one who is himself pure and who makes the impure pure. Chief tax collectors supervised networks of collectors who bought the right to collect taxes and profited by overcharging — Zacchaeus was wealthy through the systemic exploitation his position enabled.</p>",
"3": "<p>'He was seeking to see who Jesus was' — Zacchaeus's seeking (ezētei idein — he was continually seeking to see) anticipates the shepherd-seeking language of ch. 15 and the Son of Man's mission statement in v.10. The seeker and the Sought are converging. 'But on account of the crowd he could not, because he was small in stature' — the social dimension: the crowd around Jesus (the righteous, the acceptable) blocked access to Jesus for the man whom they excluded. Christ's mission requires breaking through the crowd's exclusion to reach the one the crowd overlooks.</p>",
"4": "<p>'So he ran on ahead and climbed up into a sycamore-fig tree to see him, for he was about to pass that way' — Zacchaeus's running and climbing (anabainō — used of going up to Jerusalem, going up to the temple) is the extravagant, dignity-abandoning effort of a wealthy man seeking to see Christ. The sycamore-fig (sykomōraian) was considered a lowly tree whose fruit was food for the poor — the wealthy Zacchaeus climbs a poor man's tree to see the one who has come for the poor. The posture of seeking Christ (running, climbing above the crowd) is itself an image of faith: any dignity must be abandoned to see him.</p>",
"5": "<p>'When Jesus came to the place, he looked up and said to him, Zacchaeus, hurry and come down, for I must stay at your house today' — the divine initiative: Christ looks up (anablepsas) to where Zacchaeus is — the gaze of the Good Shepherd who has come seeking this particular lost sheep. He calls him by name (as the shepherd calls his own sheep by name, John 10:3). 'I must stay' (dei — divine necessity, the same word as 2:49, 4:43, 9:22, 13:33) — the Christ-visit to Zacchaeus's house is a divine appointment, not an accident of the road. Salvation came looking for Zacchaeus before Zacchaeus found it.</p>",
"6": "<p>'So he hurried and came down and received him joyfully' — Zacchaeus's immediate response (speuō — hurry; katebē — came down at once; hypedesato — welcomed/received) is the model of faith's response to Christ's summons. He does not negotiate, delay, or calculate the social cost of hosting this controversial figure. The joy (chairōn — rejoicing) of his reception echoes the joy of the kingdom's finding (15:5, 9, 32 — the joy of the shepherd, the woman, the father). The found man rejoices; the rejoicing is not manufactured piety but the natural response to being seen and sought by name.</p>",
"7": "<p>'And when they saw it, they all grumbled, saying, He has gone in to be the guest of a man who is a sinner' — the crowd's grumbling (diagongyzō — the murmuring of 15:2, the wilderness-murmuring of the LXX) at Jesus's choice of table fellowship is the persistent pattern of religious rejection. They see the act (went to a sinner's house) without seeing the mission (came to seek and save the lost, v.10). Their grumbling contrasts with Zacchaeus's joy: those outside Christ's purpose grumble at his inclusions; those included by grace rejoice at his arrival.</p>",
"8": "<p>'And Zacchaeus stood and said to the Lord, Behold, Lord, the half of my goods I give to the poor. And if I have defrauded anyone of anything, I restore it fourfold' — the changed Zacchaeus stands (statheis — a posture of declaration, public commitment) and speaks kingdom-economics: half of wealth redistributed to the poor (cf. the rich young ruler, 18:22, who would not part with anything), and fourfold restitution for fraud (beyond the Mosaic 20% surcharge of Num 5:7 — he offers Zacchaeus-law: 400%). This is not the condition of his salvation but its fruit — the evidence that 'salvation has come to this house' (v.9) is economic transformation.</p>",
"9": "<p>'And Jesus said to him, Today salvation has come to this house, since he also is a son of Abraham' — 'today' (sēmeron — the eschatological today of 2:11, 4:21, 23:43) marks the arrival of the kingdom's reality in this home. 'Salvation has come' (sōtēria — the word used for the messianic salvation of 1:69, 1:71, 1:77, 3:6) to this house because the Savior is in this house. 'Son of Abraham' reclaims Zacchaeus for the covenant community from which his occupation excluded him: the tax collector who forfeited his covenant standing by Roman service is restored as a covenant son by Christ's declaration. The covenant comes to him; he does not first come to the covenant.</p>",
"10": "<p>Already present.</p>",
"11": "<p>'As they heard these things, he proceeded to tell a parable, because he was near to Jerusalem, and because they supposed that the kingdom of God was to appear immediately' — the Zacchaeus episode generates false expectations: the crowd, hearing about the kingdom's arrival in this house, expects immediate political-messianic fulfillment at Jerusalem. The parable of the minas corrects this expectation: the kingdom has a delay structure — the king goes away, entrusts assets to servants, and returns for the accounting. The ascension (the king going away) and the parousia (the king's return) frame the present age as the time of faithful stewardship, not immediate triumph.</p>",
"12": "<p>'He said therefore, A nobleman went into a far country to receive for himself a kingdom and then return' — the parable's nobleman who travels to receive a kingdom and returns to rule reflects the Herodian practice: Archelaus, son of Herod the Great, literally went to Rome to receive his kingdom from Augustus and returned to rule Judaea. The crowd would recognize the social mechanism. Christ is the greater nobleman who goes away (the Ascension) to receive the kingdom from the Father (Dan 7:13-14 — 'he was given dominion, glory and a kingdom') and who will return to rule (Rev 11:15 — 'the kingdoms of the world have become the kingdom of our Lord').</p>",
"13": "<p>'Calling ten of his servants, he gave them ten minas, and said to them, Engage in business until I come' — the entrusted minas (one mina = approximately three months' wages — a modest but real amount) are the resources of the kingdom entrusted to servants during the master's absence. 'Engage in business until I come' (pragmateusasthe hōs erchomai) is the charter for the church age: the time between Ascension and Parousia is the time for kingdom-faithfulness with entrusted resources. The servant's mandate during the absence is not waiting but working; not preservation but multiplication.</p>",
"14": "<p>'But his citizens hated him and sent a delegation after him, saying, We do not want this man to reign over us' — the citizens' rejection of the nobleman mirrors the Jewish leadership's rejection of Christ's messianic claim. 'We do not want this man to reign over us' is the cry of 23:21 ('Crucify him') and 23:18 ('Away with this man') — the explicit rejection of Christ's lordship by those who should have been his citizens. The parable embeds the Passion narrative within itself: the king who goes away is also the king who is rejected by his own people (John 1:11 — 'he came to his own, and his own people did not receive him').</p>",
"15": "<p>'When he returned, having received the kingdom, he ordered these servants to whom he had given the money to be called to him, that he might know what they had gained by doing business' — the return of the king with the received kingdom is the Parousia: Christ returns from the Father's presence with the kingdom formally conferred (1 Cor 15:24-25 — 'then comes the end, when he delivers the kingdom to God the Father after destroying every rule and every authority and power'). The accounting (logos — reckoning) at the return is the eschatological judgment of servants according to their stewardship. The return is certain; only its timing is unspecified.</p>",
"16": "<p>'The first came before him, saying, Lord, your mina has made ten minas more' — the first servant's tenfold return on the entrusted mina is the maximum fidelity: the one mina given has produced ten through active kingdom-engagement during the master's absence. 'Your mina' acknowledges that the resource was never the servant's own — it was always the master's, entrusted for multiplication. The faithful servant does not confuse stewardship with ownership. Christ who is 'faithful over God's house as a son' (Heb 3:6) is the model: he received the Spirit without measure (John 3:34) and multiplied its fruit in his ministry.</p>",
"17": "<p>'And he said to him, Well done, good servant! Because you have been faithful in a very little, you shall have authority over ten cities' — the commendation 'well done' (euge — a term of warm approval, not merely formal recognition) and the reward-proportioned-to-faithfulness (ten cities for ten minas returned) is the kingdom's economics: present faithful stewardship determines future kingdom-authority. The 'very little' (elachistos) of one mina's stewardship is the training-ground for the enormous authority of the new-creation governance. Those faithful in what seems little to the world are entrusted with what is great in the kingdom.</p>",
"18": "<p>'And the second came, saying, Lord, your mina has made five minas' — the second servant's fivefold return (compared to the first's tenfold) represents faithful stewardship at a different scale of fruitfulness. Both are commended; the reward is proportional. This is the kingdom's equity: 'to each according to his work' (Rev 22:12) — not equality of outcome but proportionality of reward to faithfulness. The servant who produces five is not reproached for not producing ten; the servant who produces zero is reproached for not engaging at all (vv.20-24). What matters is faithful engagement, not a predetermined result.</p>",
"19": "<p>'And he said to him, And you are to be over five cities' — the second servant receives authority over five cities — half of the first servant's reward but still an enormous kingdom-inheritance. The city-authority given to faithful servants in the parable anticipates the new-creation governance language of Revelation (2:26-27 — 'the one who conquers and who keeps my works until the end... I will give him authority over the nations'; 20:4-6 — reign of the saints). The faithful stewardship of the present age qualifies for participation in the governance of the age to come.</p>",
"20": "<p>'Then another came, saying, Lord, here is your mina, which I kept laid away in a handkerchief' — the unfaithful servant's preservation of the mina (perfectly intact, no loss, no risk) is the image of fearful religion without engagement. The handkerchief (soudarion — a cloth for wiping sweat) is a mundane, impermanent container for something of kingdom significance. The servant has preserved what he was given without allowing it to do anything. This is the image of the church that buries the gospel in institutional preservation rather than kingdom-extension — keeping it safe instead of multiplying it.</p>",
"21": "<p>'For I was afraid of you, because you are a severe man. You take what you did not deposit, and reap what you did not sow' — the unfaithful servant's fear-logic (the master is hard, so I played it safe) reveals a fundamental misunderstanding of the master's character. He knows the master's severity but does not know the master's generosity (the entrusting of resources, the promise of reward). The servant who fears the master's demands without trusting the master's generosity will be paralyzed. This is the difference between legalistic religion (fear of God's demands) and gospel-shaped faithfulness (trust in God's generosity enabling obedient engagement).</p>",
"22": "<p>'He said to him, I will condemn you with your own words, you wicked servant!' — the servant is judged by his own stated reasoning: if you knew I was a severe man who takes what I didn't deposit, then precisely for that reason you should have put the mina in the bank rather than in a handkerchief. The logic of his own fear-assessment condemns him: his inaction is inconsistent even with his stated understanding of the master. The eschatological judgment uses the servant's own reasoning as the standard — 'by your words you will be justified, and by your words you will be condemned' (Matt 12:37).</p>",
"23": "<p>'Why then did you not put my money in the bank, and at my return I might have collected it with interest?' — the minimum requirement (bank interest) is the floor that even the fearful servant could have met. The servant did not meet even the minimum. The parable teaches that there is no neutral position in kingdom-stewardship: inaction is itself a choice with consequences. Doing nothing with what Christ has entrusted is not a safe option — it is a guaranteed loss. The cross was not Christ's 'safe option' (Gethsemane, 22:42); his faithful engagement with the Father's mission, at maximum cost, is the model of what kingdom-stewardship looks like.</p>",
"24": "<p>'And he said to those who stood by, Take the mina from him, and give it to the one who has the ten minas' — the reallocation of the unfaithful servant's mina to the one with ten is the kingdom's economics in its most confronting form: to the faithful, more is entrusted; from the unfaithful, what little they have is taken. This is the operating principle of spiritual growth: faithfulness in the received creates capacity for more; unfaithfulness atrophies the capacity received. The faithful servant's ten-city authority is the result of ten-mina faithfulness; the unfaithful servant's loss is the result of zero-mina faithfulness.</p>",
"25": "<p>'And they said to him, Lord, he has ten minas!' — the bystanders' objection to giving the already-wealthy servant more captures the common-sense fairness objection to the kingdom's economics. Why give the already-productive servant more? The kingdom's economics are not distributive justice (equal shares to all) but productive justice (resources to those who will use them). Christ who has received all authority (Matt 28:18 — 'all authority in heaven and on earth has been given to me') and to whom all things are being subjected (1 Cor 15:27-28) is the supreme recipient of the kingdom's 'to the faithful, more.' He receives everything because he was faithful in everything.</p>",
"26": "<p>'I tell you that to everyone who has, more will be given, but from the one who has not, even what he has will be taken away' — the kingdom's axiom of spiritual multiplication is the law of grace: grace given and received produces more grace; grace given and unused — treated as a possession to hoard rather than a resource to deploy — is lost. This is the Reformation insight about faith: saving faith is always living faith (active, engaging, producing fruit); dead faith is not merely insufficient — it demonstrates that the faith was never truly present. What appears to be preserved faith that produces nothing may be no faith at all.</p>",
"27": "<p>'But as for these enemies of mine, who did not want me to reign over them, bring them here and slaughter them before me' — the judgment of the citizens who refused the king's reign is the eschatological judgment language of the parable's political frame. This is not a prescriptive model for Christian violence but the parable's portrayal of the Parousia's judgment: those who have persistently refused Christ's lordship throughout the age of stewardship will face his judgment at his return. Rev 19:11-21 uses similar language for the same reality: the returning king's judgment of those who opposed him. The parable ends with both the reward of faithfulness and the judgment of refusal.</p>",
"28": "<p>'And when he had said these things, he went on ahead, going up to Jerusalem' — the resumed journey to Jerusalem (anabainōn — going up, the standard verb for ascending to Jerusalem) marks the resumption of the Passion journey after the Jericho parenthesis (Zacchaeus, minas parable). 'Going up ahead' (emprosthen poreuomenos — going before them) is the image of the shepherd going before the flock (John 10:4 — 'he goes before them, and the sheep follow him'). Christ leads the way to the city where he will die. His going up is voluntary, purposeful, and ahead of all who follow — he arrives at the cross before any disciple arrives at their own.</p>",
"29": "<p>'When he drew near to Bethphage and Bethany, at the mount that is called Olivet, he sent two of the disciples' — the Mount of Olives is the prophetic location of messianic arrival (Zech 14:4 — 'On that day his feet shall stand on the Mount of Olives that lies before Jerusalem on the east') and of Christ's return (Acts 1:11-12 — the disciples return from Olivet after the Ascension, told that 'this Jesus... will come in the same way'). The triumphal entry from the Mount of Olives is the first-coming fulfillment of Zechariah's messianic arrival; the Ascension from the same mount points to the second-coming fulfillment.</p>",
"30": "<p>'Saying, Go into the village in front of you, where on entering you will find a colt tied, on which no one has ever yet sat. Untie it and bring it here' — the unridden colt is a detail of ritual purity: a new animal not broken for human use is appropriate for sacred purposes (Num 19:2 — the red heifer 'which has never been yoked'; 1 Sam 6:7 — the new cart with cows that 'have never borne a yoke'). Christ comes to Jerusalem on a vehicle consecrated by its newness to his use. The colt that has never carried a human burden will carry the one who will bear every human burden. The arranged colt also demonstrates Christ's foreknowledge and sovereignty over events.</p>",
"31": "<p>'If anyone asks you, Why are you untying it? you shall say this: The Lord has need of it' — 'the Lord has need' (ho Kyrios autou chreian echei — the Lord needs it) is the claim of divine sovereignty in ordinary provision. The title 'Lord' (Kyrios) applied to Jesus here is the same as the LXX's title for YHWH. The Lord of the universe who needs nothing (Acts 17:25 — 'he is not served by human hands, as though he needed anything') paradoxically 'needs' a colt — the same paradox as the Word who needs nothing assuming flesh, the King who needs nothing needing a manger. His 'need' is always the need of the mission, not the need of lack.</p>",
"32": "<p>'So those who were sent went away and found it just as he had told them' — the disciples' finding of the colt exactly as Christ described confirms his prophetic foreknowledge. This small fulfillment (colt exactly where he said) prepares the disciples to trust his larger prophetic word about Jerusalem's destruction (vv.41-44), his death (9:22, 18:31-33), and his resurrection. Christ's precision in small details is the ground of faith for his large promises. Every verified small prophecy strengthens confidence in the unverified large ones.</p>",
"33": "<p>'And as they were untying the colt, its owners said to them, Why are you untying the colt?' — the owners' question (the same question Christ had anticipated in v.31) is answered by the disciples' use of the prescribed phrase. The prepared answer serves as the key that unlocks the colt's release. This is the pattern of kingdom provision through prophetic preparation: Christ announces; disciples obey; provision follows. The owners' willingness to release their colt to 'the Lord's need' is itself a small act of faith — they yield to a claim they have not directly heard from its source.</p>",
"34": "<p>'And they said, The Lord has need of it' — the disciples' repetition of Christ's phrase (ho Kyrios autou chreian echei) as the key that releases the colt is the model of proclamation: repeating what Christ has said, not generating new authority from themselves. The disciples' authority to release the colt comes from the word they carry, not from their own status. This is the apostolic pattern: 'we do not preach ourselves, but Jesus Christ as Lord, with ourselves as your servants for Jesus's sake' (2 Cor 4:5). The phrase 'the Lord has need' opens every door that needs to be opened for the mission.</p>",
"35": "<p>'And they brought it to Jesus, and throwing their cloaks on the colt, they set Jesus on it' — the disciples' cloaks thrown on the colt are the improvised saddle of a spontaneous but prophetically planned event. The act echoes 2 Kings 9:13 — when Jehu was acclaimed king, 'they hurried and took their garments and put them under him on the bare steps.' The disciples' garment-laying is the gesture of royal acclamation: they are making a throne for the king. Their recognition (however imperfect) of Christ's royalty is the beginning of the Palm Sunday proclamation that will reach its crescendo at v.38.</p>",
"36": "<p>'And as he rode along, they spread their cloaks on the road' — the spreading of cloaks on the road is the ancient gesture of honor-pavment before royalty (2 Kings 9:13 again — the surface made worthy of the king's passage). The road of Christ's entry becomes a carpet of the disciples' possessions. The irony is that the king who comes in meekness on an unridden colt (the warrior-king rides a warhorse; Zech 9:9 — 'he is humble and mounted on a donkey') receives a warrior-king's honor. He comes in peace; they honor him as a victor. The tension between the mode of his coming and the mode of his reception captures the Passion week's paradox.</p>",
"37": "<p>'As he was drawing near — already on the way down the Mount of Olives — the whole multitude of his disciples began to rejoice and praise God with a loud voice for all the mighty works they had seen' — the praise-burst (chairontes — rejoicing) on the Mount of Olives descent recalls the joy of angels at the birth (2:10-14 — 'great joy... glory to God in the highest') and anticipates the joy of the Resurrection (24:52 — 'they returned to Jerusalem with great joy'). The mighty works (dynameis — the healings, exorcisms, resurrections) are the grounds of the praise: they have seen who he is by what he has done.</p>",
"38": "<p>'Blessed is the King who comes in the name of the Lord! Peace in heaven and glory in the highest!' — the disciples' acclamation quotes Ps 118:26 ('Blessed is he who comes in the name of the LORD!') with the addition of 'the King' — making explicit what the Psalm implies. 'Peace in heaven and glory in the highest' inverts the angels' birth-announcement (2:14 — 'Glory to God in the highest, and on earth peace') — from earth-directed peace to heaven-directed peace. The kingdom's arrival in the King's person is the making-of-peace between heaven and earth that his cross will accomplish (Col 1:20 — 'through him to reconcile all things... making peace by the blood of his cross').</p>",
"39": "<p>'And some of the Pharisees in the crowd said to him, Teacher, rebuke your disciples' — the Pharisees' demand that Jesus silence the disciples is the demand to suppress the messianic acclamation. Their address ('Teacher' — Didaskale, not 'Lord') positions them outside the acclamation. They hear the disciples' praise as blasphemous presumption or dangerous sedition; Jesus hears it as the right response to who he is. The Pharisees who cannot receive the disciples' praise of the King will hear from the stones instead (v.40). Those who suppress the creation's praise do not silence it — they remove themselves from it.</p>",
"40": "<p>'He answered, I tell you, if these were silent, the stones would cry out' — the stones crying out (hoi lithoi kraxousin) is the declaration that the creation itself recognizes its King's arrival. The stones of creation would praise what the Pharisees would suppress. This is the Christological claim embedded in creation-language: the King who comes is the one through whom all things were made (John 1:3; Col 1:16), and the creation — though it groans (Rom 8:22) — recognizes its Maker. Every created thing is a potential witness to Christ's glory; the Pharisees who suppress human praise cannot suppress the creation's.</p>",
"41": "<p>'And when he drew near and saw the city, he wept over it' — Jesus weeping over Jerusalem (eklaien — he wept, the same verb as John 11:35 at Lazarus's tomb) in the middle of the triumphal procession is the supreme irony of Palm Sunday: the King acclaimed by the crowd weeps over the city that will reject him. His tears are not self-pity but prophetic grief: he sees the coming destruction that Jerusalem's rejection of him will bring. The weeping King is the image of the God who weeps over Israel's judgment (Jer 8:21 — 'I am hurt at the grief of my people'; Isa 22:4 — 'I will weep bitterly'). God has come in person to weep over his city.</p>",
"42": "<p>'Saying, Would that you, even you, had known on this day the things that make for peace! But now they are hidden from your eyes' — 'the things that make for peace' (ta pros eirēnēn) are the terms of the kingdom that Christ offers: repentance, recognition of the visitation, reception of the King. Jerusalem has not recognized what makes for peace because her spiritual eyes are closed — not by divine arbitrariness but by the accumulated rejection that has hardened the city's heart. 'Hidden from your eyes' is the divine passive of judicial blindness: the long refusal of the prophets (13:34) has brought the concealment of salvific knowledge. Christ weeps at the blindness his judgment makes necessary.</p>",
"43": "<p>'For the days will come upon you, when your enemies will set up a barricade around you and surround you and hem you in on every side' — the prophecy of Jerusalem's siege is the historical prediction fulfilled in 70 CE when Titus and the Roman army surrounded Jerusalem with a wall of circumvallation (Josephus, Jewish War V.12.1-2 describes the Roman siege works in detail). Christ's prophetic specificity (the barricade, the surrounding, the hemming in) is the precision of divine foreknowledge. The coming judgment is the natural consequence of rejecting the one who offered peace (v.42); it is not divine vengeance but the inevitable result of refusing the peace-maker.</p>",
"44": "<p>'And tear you down to the ground, you and your children within you. And they will not leave one stone upon another in you, because you did not know the time of your visitation' — 'the time of your visitation' (ton kairon tēs episkopēs sou — the season of God's coming-to-visit) is the Incarnation-moment: God has come in person to Jerusalem, walking its streets, teaching in its temple, weeping at its walls. Jerusalem did not 'know' this visitation — she did not recognize her God in the flesh. The consequence (stones torn down) is proportionate to the missed opportunity: the city that missed the living Stone (1 Pet 2:4-8) will have no stones left standing.</p>",
"45": "<p>'And he entered the temple and began to drive out those who sold' — the temple cleansing follows immediately upon the entry and the weeping-over-Jerusalem. The cleansing of the temple is a prophetic-symbolic act: the King who arrives to his city (v.38) and finds corruption in his Father's house (2:49 — 'my Father's house') acts with prophetic authority to restore its purpose. The short Lukan account (without the money-changers and dove-sellers detail of Matthew/Mark) focuses the act: driving out those who have made the temple a commercial space. Christ's action is the enacted judgment of his prophetic words about the temple (v.44 — the stones torn down).</p>",
"46": "<p>'Saying to them, It is written, My house shall be a house of prayer, but you have made it a den of robbers' — the quotation combines Isa 56:7 ('my house shall be called a house of prayer for all peoples') and Jer 7:11 ('Has this house, which is called by my name, become a den of robbers in your eyes?'). The Jeremiah context (Jer 7) is the prophet's temple sermon warning that the temple will be destroyed like Shiloh if Israel's wickedness continues — a sermon that led to Jeremiah's near-death (Jer 26). Christ's use of Jeremiah in the temple carries the same weight: judgment is coming on the house that has become a den of robbers, as it came on Shiloh.</p>",
"47": "<p>'And he was teaching daily in the temple. The chief priests and the scribes and the principal men of the people were seeking to destroy him' — the daily teaching in the temple (Lk 21:37 confirms this pattern) is Christ's occupation of his Father's house during the Passion week. He comes each day to the place where the authorities seek his death and teaches without protection other than the crowd (v.48). This is the posture of the King who knows he is going to the cross and teaches freely until the hour arrives. His boldness is not bravado but confidence in the Father's timing: 'my hour has not yet come' (John 2:4; 7:6, 8; 8:20; 13:1).</p>",
"48": "<p>'But they did not find anything they could do, for all the people were hanging on his words' — the people's attentiveness (exekremato autou — were hanging on him, the verb used for hanging on a cliff-edge) is the literal protection of Christ's life during Passion week: the authorities could not act because the crowds would riot (22:2 — 'they feared the people'). Christ's popularity is the human shield that preserves him until the hour the Father has determined. The Father's protection is accomplished through ordinary means: a crowd of people who cannot get enough of what Jesus is saying. Providence works through the attentiveness of those who hang on his words.</p>"
},
"20": {
"1": "<p>'One day, as Jesus was teaching the people in the temple and preaching the gospel, the chief priests and the scribes with the elders came up' — the confrontation begins mid-teaching: the authorities interrupt the gospel-proclamation in the temple. Their timing (coming to him while he teaches) is the pattern of the opposition to Christ throughout Luke: they come to him while he is doing what he is supposed to do (healing, teaching, forgiving) and question his right to do it. Their interruption of the gospel is itself an image of what the Passion will accomplish: they stop his preaching by killing him, but his death becomes the most powerful proclamation of the gospel.</p>",
"2": "<p>'And they said to him, Tell us by what authority you do these things, or who it is that gave you this authority' — the authority-question (exousia — the right and power to act as one does) is the fundamental Christological question: from where does Jesus derive his authority? The authorities expect to trap him: if he claims divine authority, they charge blasphemy; if he claims human authority, he can be dismissed. The question is more important than they realize: Christ's authority is the Father's own authority (John 5:27 — 'he has given him authority to execute judgment'), given before the foundation of the world. Every answer he gives is either received or rejected as the word of the Son of God.</p>",
"3": "<p>'He answered them, I also will ask you a question. Now tell me' — the rabbinic counter-question (answering a question with a question) is Christ's method throughout the controversy narratives (10:26, 36; 12:14; 20:17, 41). His counter-question is not evasion but diagnosis: the answer to the authority-question depends on how they respond to the Baptist's authority-question. The two questions are logically linked (v.4 makes the connection). Christ's wisdom in question-answering — using their own framework to reveal their bad faith — is the wisdom of the one who 'knew what was in man' (John 2:25).</p>",
"4": "<p>'Was the baptism of John from heaven or from man?' — the John-question forces the authorities to evaluate authority-claims publicly. The Baptist's authority (from heaven or from man?) is the same kind of question as Christ's authority. If they answer 'from heaven,' they must explain why they did not believe him. If they answer 'from man,' they risk the crowd's anger (John was popularly regarded as a prophet, v.6). The question exposes that their problem with authority-claims is not epistemological (they cannot determine authority) but volitional: they will not acknowledge any authority that requires submission to Christ.</p>",
"5": "<p>'And they discussed it with one another, saying, If we say, From heaven, he will say, Why did you not believe him?' — the authorities' internal discussion is exposed by Luke (the narrator gives us their reasoning). Their calculation is political: both answers lose. The 'from heaven' answer requires them to explain why they rejected John's testimony about Jesus. Their failure to believe John is their failure to believe the voice of the Father who sent John to prepare the way (Mal 3:1; Luke 1:17, 76). The calculation they perform is not 'what is true?' but 'what answer is least costly?' — the standard of bad-faith reasoning.</p>",
"6": "<p>'But if we say, From man, all the people will stone us, for they are convinced that John was a prophet' — the stoning-threat (they will stone us — katalithesei — is the threat against false teachers, Deut 13:10; 17:7) reveals that the authorities recognize the crowd's prophetic intuitions even while they resist them. The crowd's conviction that John was a prophet is the crowd's implicit Christology: if John was the forerunner, then he who comes after John is greater. The authorities who fear the crowd's stoning if they deny John's prophetic status are afraid of the crowd's implicit Christology about Jesus. Their fear of the crowd is their fear of what the crowd's correct intuitions point to.</p>",
"7": "<p>'So they answered that they did not know where it came from' — the authorities' 'we do not know' is not honest agnosticism but deliberate non-commitment — the refusal to take a public position on John's authority to avoid the consequences of either answer. This is the posture of the one who will not be convicted by the evidence before them. Christ who is the Truth (John 14:6) stands before those who choose not-knowing over the costly truth. Their 'we do not know' is the most honest self-revelation of the narrative: they have chosen not to know, because knowing requires submitting.</p>",
"8": "<p>'And Jesus said to them, Neither will I tell you by what authority I do these things' — Christ's withholding of the authority-answer is not coyness but justice: he will not give explicit self-testimony to those who have demonstrated by their evasion that they will not receive it. John 10:25-26 makes the same point: 'I told you, and you do not believe. The works that I do in my Father's name bear witness about me, but you do not believe because you are not among my sheep.' The answer to the authority-question is embedded in every healing, every teaching, every confrontation — those with ears to hear have already received the answer; those who choose not to hear will not be given it explicitly.</p>",
"9": "<p>'And he began to tell the people this parable: A man planted a vineyard and let it out to tenants and went into another country for a long while' — the Vineyard parable draws on Isa 5:1-7 (the song of the vineyard — 'the vineyard of the LORD of hosts is the house of Israel') and thereby identifies the owner as God, the vineyard as Israel, and the tenants as Israel's leaders. The 'long while' (chronous hikanous — considerable time) is the long period of OT history during which God entrusted Israel to its leaders. The parable is a compressed salvation-history: the planting of Israel, the tenancy of its leadership, and the sending of God's servants.</p>",
"10": "<p>'When the time came, he sent a servant to the tenants, so that they would give him some of the fruit of the vineyard. But the tenants beat him and sent him away empty-handed' — the servant sent for the fruit of the vineyard is the prophet sent by God for Israel's covenant-faithfulness. The beating and empty-handed sending is the rejection of the prophets (Acts 7:52 — 'which of the prophets did your fathers not persecute?'). The pattern is: God sends; Israel rejects; God sends again. The three servants (vv.10-12) are the three periods of prophetic witness (the prophets who were beaten, killed, and stoned — Heb 11:36-38). The pattern builds to its climax.</p>",
"11": "<p>'And he sent another servant. But they also beat and treated him shamefully and sent him away empty-handed' — the second servant treated shamefully (atimasantes — dishonored, stripped of honor) represents the intensification of Israel's rejection of prophetic witness. Each successive rejection deepens the guilt: the first rejection might be ignorance; the second is pattern; the third (v.12) is systematic. The honor-shame dimension (treating the master's servants shamefully) is significant: the owner of the vineyard has his honor attacked through the treatment of his representatives. Every prophet dishonored is the Lord himself dishonored (Luke 10:16 — 'he who rejects you rejects me').</p>",
"12": "<p>'And he sent yet a third. This one also they wounded and cast out' — the third servant wounded and thrown out completes the trilogy of prophetic rejection. The escalation (beaten → beaten shamefully → wounded and thrown out) mirrors the escalation of Israel's prophetic rejection through the OT. The 'wounded' (traumatisantes — the verb used in Acts 19:16 for the sons of Sceva being wounded by the demon-possessed man) suggests serious physical injury. The parable is not merely historical allegory; it is the self-understanding of Christ as he moves toward Jerusalem — he knows he is the final Servant, and the pattern he is describing is his own approaching fate.</p>",
"13": "<p>'Then the owner of the vineyard said, What shall I do? I will send my beloved son; perhaps they will respect him' — 'my beloved son' (ton huion mou ton agapēton) is the exact phrase from the Baptism (3:22 — 'You are my beloved Son') and the Transfiguration (9:35 — 'This is my Son, my Chosen One'). The vineyard-owner's sending of his son is the Father's sending of his Son: the Incarnation as the final, decisive, supremely hopeful mission. 'Perhaps they will respect him' is not divine uncertainty but the structure of the gift: the Son comes in freedom, not in coercion, to a people who could receive or reject him. The 'perhaps' of the gift preserves the tenants' dignity as moral agents.</p>",
"14": "<p>'But when the tenants saw him, they said to one another, This is the heir. Let us kill him, so that the inheritance may become ours' — the tenants' recognition of the son ('this is the heir') followed by the murder-plot is the parable's most searching detail: they kill him precisely because they recognize him. The Jewish leadership's rejection of Jesus is not ignorance (v.5 — they calculated; v.6 — they feared; v.14 — they recognized) but deliberate suppression of the truth they know. 'That the inheritance may become ours' is the satanic logic: kill the Son, seize the inheritance. It is the logic of Adam (Gen 3 — 'you will be like God') applied to the Incarnation.</p>",
"15": "<p>'And they threw him out of the vineyard and killed him. What then will the owner of the vineyard do to them?' — the son thrown out of the vineyard and killed is the Christ crucified outside the city walls (Heb 13:12 — 'Jesus also suffered outside the gate'). The vineyard-throwing corresponds to the city-ejection: Jerusalem throws out its King. The rhetorical question 'What then will the owner do?' is the Passion's question: what does the Father do with those who kill his Son? The answer (v.16) is the destruction of the tenants and the giving of the vineyard to others — the judgment of 70 CE and the extension of the kingdom to the Gentiles.</p>",
"16": "<p>'He will come and destroy those tenants and give the vineyard to others.' When they heard this, they said, Surely not! — the people's horrified 'surely not' (mē genoito — the Pauline 'by no means!') at the parable's judgment reveals their recognition of what the parable is saying: Jesus is predicting the end of the Jewish leadership's stewardship of the covenant and its transfer to others (the Gentile mission). Their horror is partly piety (how could God destroy his own tenants?) and partly self-interest (they are the tenants). Christ is announcing what the cross and resurrection will accomplish: a new covenant community that includes those the old leaders excluded.</p>",
"17": "<p>'But he looked directly at them and said, What then is this that is written: The stone that the builders rejected has become the cornerstone?' — Ps 118:22 (the same psalm as the triumphal entry, v.38) provides the scriptural interpretation of the parable: the rejected son is the rejected stone. The builders (the Jewish leadership) reject the stone that the architect (God the Father) has chosen as the cornerstone. The cornerstone (kephalēn gōnias — head of the corner) is the stone that determines the alignment of every other stone in the building — the one rejected stone is the one on whom the entire new edifice depends. 1 Pet 2:4-8 applies this text explicitly to Christ as the living stone.</p>",
"18": "<p>'Everyone who falls on that stone will be broken to pieces, and when it falls on anyone, it will crush him' — the two modes of relating to the cornerstone-Christ: falling on it (stumbling, being broken — the stumbling-block of 1 Cor 1:23, the offense of the cross to both Jews and Greeks) or being crushed by it (the stone's falling on its opponents — Dan 2:34-35, 44-45, the stone cut without hands that strikes the statue and becomes a great mountain). There is no neutral relation to Christ: he is either the foundation on which one builds (Matt 7:24-25) or the stone that destroys. The two modes are faith and unbelief.</p>",
"19": "<p>'The scribes and the chief priests sought to lay hands on him at that very hour, for they perceived that he had told this parable against them, but they feared the people' — the authorities' perception (egnōsan — they knew) that the parable was aimed at them is the confirmation that the parable worked as diagnosis: they recognized themselves as the tenants who killed the son. Their response is to plan to kill him — making themselves in reality the tenants they recognized in the story. The parable creates the reality it describes: it reveals the murder-plot in the listeners' hearts, and the listeners prove the parable true by plotting murder.</p>",
"20": "<p>'So they watched him and sent spies, who pretended to be sincere, that they might catch him in something he said, so as to deliver him up to the authority and jurisdiction of the governor' — the shift to hostile surveillance (paraterēsantes — watched carefully, same verb as 14:1) via planted spies (egkathetos — a hapax legomenon, agents planted to entrap) reveals the depth of the opposition. The goal is to 'deliver him to the authority and jurisdiction of the governor' — to transfer Christ from the Jewish legal sphere to the Roman one, making him subject to capital punishment by Roman execution (crucifixion). The trap they set is the mechanism of the Passion: his own words will be used against him at the Roman trial (23:2).</p>",
"21": "<p>'So they asked him, Teacher, we know that you speak and teach rightly, and show no partiality, but truly teach the way of God' — the spies' flattery ('we know you are impartial, you truly teach God's way') is designed to lower Christ's guard by appealing to his reputation for honest teaching. The irony is that their flattery is true: Christ does speak rightly; he does show no partiality; he does truly teach the way of God. Their false praise accidentally correctly identifies who Jesus is — but they use the truth as a trap. The truth spoken to entrap is still the truth; Christ will answer from within the truth rather than the entrapment.</p>",
"22": "<p>'Is it lawful for us to give tribute to Caesar, or not?' — the tribute question is designed to impale Christ on a dilemma: if he says yes (pay tribute), he alienates the anti-Roman crowd (and possibly the Zealots who opposed tribute as violation of God's sovereignty over Israel); if he says no (don't pay tribute), he can be delivered to Pilate on a charge of sedition against Rome (the charge brought anyway in 23:2). The tribute question is the political-theological version of the Sabbath question: does a particular human authority override a divine one? Christ's answer will reframe the question entirely.</p>",
"23": "<p>'But he perceived their craftiness and said to them' — Christ's perception (katanoeō — thoroughly observed, same verb as 12:24, 27) of their craftiness (panourgia — all-working cunning, the word used for the craftiness of Satan in 2 Cor 11:3) cuts through the flattery and the trap. He sees through the spies' pretended sincerity (v.20 — hupokrinomenous — hypocrites) to their actual purpose. The one who 'knew what was in man' (John 2:25) perceives every form of human guile. His perception of their craftiness is not suspicion but the clarity of the truth-teller who recognizes falsehood immediately.</p>",
"24": "<p>'Show me a denarius. Whose likeness and inscription does it have?' They said, Caesar's — the denarius with Caesar's image and inscription (the coin of Roman imperial currency) is the visual aid for Christ's answer. The Roman tribute coin bears Caesar's image — and the image bears the image-bearer's obligation. The image-theology (tselem — image, Gen 1:26-27 — humans made in God's image) is the hinge of Christ's answer: Caesar's image on the coin establishes Caesar's claim on coins; God's image stamped on humanity establishes God's claim on humans. The answer that resolves the tribute dilemma is a deeper theology of image and obligation.</p>",
"25": "<p>'He said to them, Then render to Caesar the things that are Caesar's, and to God the things that are God's' — the two-part answer is not a division of life into religious and political spheres but a priority-ordering: Caesar's things (coins stamped with his image) to Caesar; God's things (humans stamped with his image, Gen 1:26-27) to God. The unstated implication is that Caesar's claim is real but limited — bounded by what bears his image — while God's claim encompasses everything, since everything that exists was made through the one who is himself the image of God (Col 1:15 — 'he is the image of the invisible God'). Caesar gets his coins; God gets humanity.</p>",
"26": "<p>'And they were not able in the presence of the people to catch him in what he said, but marveling at his answer they became silent' — the silence of the spies before Christ's answer is the silence of the answer that cannot be refuted. They came to catch him; they have been caught themselves — by the wisdom that turns their trap into a theological teaching moment. The 'marveling' (thaumasantes) is the response of those who encounter wisdom beyond their calculations. The trap-layers who planned to entrap Christ are left marveling at his freedom within the trap — which is itself an image of the cross: the plot to destroy him becomes the instrument of universal salvation.</p>",
"27": "<p>'There came to him some Sadducees, those who deny that there is a resurrection, and they asked him a question' — the Sadducees who 'deny that there is a resurrection' are the priestly-aristocratic party who accepted only the Torah (not the Prophets or Writings) as authoritative, and who found no resurrection doctrine in the Five Books. Their arrival after the Pharisees' tribute-trap is the second confrontation of a different kind: not political entrapment but theological challenge from a different direction. Christ will answer both the political trap and the theological challenge from the same source: the nature of God revealed in Scripture.</p>",
"28": "<p>'Saying, Teacher, Moses wrote for us that if a man's brother dies, having a wife but no children, the man must take the wife and raise up offspring for his brother' — the levirate law (Deut 25:5-6 — the brother-in-law's duty to marry the widow and preserve the family name) is the Sadducees' setup for their resurrection reductio ad absurdum. The law is real and serious (it preserves the widow's social security and the family's heritage). But the Sadducees use it to construct an absurd scenario (seven brothers, one wife) designed to make resurrection seem logically impossible. They argue from the law that resurrection undermines the law — Christ will answer that their conception of resurrection is wrong, not that the law is wrong.</p>",
"29": "<p>'Now there were seven brothers. The first took a wife, and died without children' — the seven-brothers scenario is constructed to maximize the absurdity: the maximum number of levirate obligations, all unfulfilled by death (no children), producing a situation where the resurrection would require assigning one woman to seven simultaneous husbands. The Sadducees assume that resurrection-life is exactly like this-age life with its social structures, legal arrangements, and marriage institutions. Their error is the error of assuming that the age to come is a mere continuation of this age — they have not grasped the discontinuity between the present order and the resurrection order.</p>",
"30": "<p>'And the second' — the second brother takes the widow, and likewise dies childless. The second iteration of the levirate chain deepens the absurdity the Sadducees are constructing. The serial levirate marriage scenario, whatever its historical plausibility (perhaps a reference to Tobit, where the demon killed Sarah's seven husbands), serves to pile up the logical difficulty: by the seventh iteration, the situation has become so convoluted that resurrection seems impossible to adjudicate. Christ will cut through the whole scenario by correcting the premise rather than solving the puzzle within the premise's framework.</p>",
"31": "<p>'And the third took her, and likewise all seven left no children and died' — all seven brothers married the same woman; all seven died childless. The scenario is complete: the levirate chain has run its full course without producing offspring, leaving the widow with seven sequential husbands all of whom predecease her. The Sadducees have constructed the maximum possible complication for the resurrection-claim. The complication rests on their assumption that resurrection-life maintains the marriage structures of this-age life. Christ will address this assumption directly in v.35-36, showing that the premise of the question is incorrect.</p>",
"32": "<p>'Afterward the woman also died' — the woman's death completes the cast: eight deaths (seven brothers plus the woman), no surviving children, maximum levirate complexity, maximum resurrection-puzzle. Now the question can be posed. The Sadducees have done their setup work carefully. But they have built on a false premise — the assumption that the resurrection is a resumption of present-age social arrangements — and Christ will demolish the premise before addressing the puzzle. The woman's death, too, is included in the scenario because the question 'whose wife will she be?' (v.33) requires her also to be among the resurrected.</p>",
"33": "<p>'In the resurrection, therefore, whose wife will the woman be? For the seven had her as wife' — the question is posed with studied care: 'whose wife will she be in the resurrection?' assumes that the resurrection restores the same social relationships that existed before death, including all their legal complications. It is a genuine question only if the resurrection is a return to the present social order. Christ's answer will reveal that the resurrection is not a return to the present order but a transformation into a new order — and that the question itself reveals the Sadducees' misunderstanding of what resurrection is.</p>",
"34": "<p>'And Jesus said to them, The sons of this age marry and are given in marriage' — the phrase 'the sons of this age' (hoi huioi tou aiōnos toutou) distinguishes the present age from the age to come. Marriage belongs to the present age — it is the institution God established for human flourishing and covenant-propagation in this age (Gen 2:24; Matt 19:4-6). The Sadducees have correctly observed that marriage belongs to this age; their error is assuming it belongs to the age to come in the same way. Christ affirms the institution's this-age validity while correcting its extension into the resurrection-order. He is not abolishing marriage but situating it properly within salvation-history.</p>",
"35": "<p>'But those who are considered worthy to attain to that age and to the resurrection from the dead neither marry nor are given in marriage' — 'considered worthy' (kataxiōthentes — those deemed worthy to attain) is not merit-language but eschatological status-language: those who attain the resurrection-age are those who are in Christ (1 Cor 15:22 — 'in Christ shall all be made alive'). They 'neither marry nor are given in marriage' — not because marriage is sinful or inferior but because the age to come has a different social order that does not require the institutions of this age (propagation, covenant-securing through family, protection of the widow through levirate). The resurrection order is qualitatively different, not merely quantitatively extended.</p>",
"36": "<p>'For they cannot die anymore, because they are equal to angels and are sons of God, being sons of the resurrection' — the deathlessness of resurrection-life is the root of the marriage-institution's transformation: marriage as an institution serves this age partly as propagation (if no one died, propagation would eventually be unnecessary). In the age to come, 'they cannot die anymore' — the institution's propagation-purpose has been accomplished; the family of God is complete. 'Equal to angels' (isangeloi — a hapax in the NT) specifies the deathlessness, not the asexuality or non-embodiment of resurrection; the Sadducees who denied angels (Acts 23:8) are now confronted with angelomorphic resurrection-life as the answer to their question.</p>",
"37": "<p>'But that the dead are raised, even Moses showed, in the passage about the bush, where he calls the Lord the God of Abraham and the God of Isaac and the God of Jacob' — Christ's answer to the Sadducees uses their own authority (Moses, whose Torah they exclusively accepted) to prove resurrection. The burning bush passage (Exod 3:6) is the proof-text: God declares 'I am the God of Abraham, Isaac, and Jacob' — present tense, 'I am,' not 'I was.' If God's present relationship with Abraham, Isaac, and Jacob is real, those patriarchs must exist. The present-tense 'I am' of God's covenant-declaration requires the aliveness of the covenant partners. Moses proves resurrection to the Sadducees from their own canon.</p>",
"38": "<p>'Now he is not God of the dead, but of the living, for all live to him' — the theological principle behind the burning-bush proof: God cannot be 'God of' those who simply do not exist. If God is the God of Abraham, Isaac, and Jacob, then those three men are alive — their bodies await resurrection, but their persons are alive to God. 'All live to him' (pantes gar autō zōsin) is the eschatological affirmation: from God's perspective, all who are in covenant with him live — death is not the end of the covenant relationship but a threshold within it. Christ who is himself 'the resurrection and the life' (John 11:25) grounds this in his own person: in him, all live.</p>",
"39": "<p>'Then some of the scribes answered, Teacher, you have spoken well' — the scribes' commendation of Christ's answer to the Sadducees is from people who shared the Pharisaic belief in resurrection (Acts 23:8 — the Pharisees acknowledged both resurrection and angels). They recognize Christ's answer as correct within their own theological framework — the present-tense God-of requires living covenant-partners. The commendation is honest and ironic: the scribes who are among those planning Christ's death (19:47) affirm the truth of his teaching about resurrection. They affirm what he teaches while planning to kill the one in whom the teaching is embodied.</p>",
"40": "<p>'For they no longer dared to ask him any question' — the silence of all opponents after the resurrection-question marks the end of the Passion-week controversy dialogues. The tribute-question, the authority-question, and the resurrection-question have all been answered with wisdom that leaves the questioners silenced. The authorities' silence is not the silence of assent but the silence of strategic withdrawal — they will move from public questioning to private conspiracy (22:3-6). When argument fails, they resort to betrayal. Christ's victory in the controversy dialogues will be reversed (humanly speaking) by the Judas-betrayal that their silence leads them to arrange.</p>",
"41": "<p>'But he said to them, How can they say that the Christ is David's son?' — having silenced his opponents, Christ now takes the initiative with his own question: the riddle of the Christ's identity as simultaneously David's son and David's Lord. The question 'how can they say that the Christ is David's son?' is not a denial of Davidic descent (Luke has established it in the genealogy, 3:31; and in the angel's words, 1:32) but a challenge to those whose entire messianic expectation is exhausted by Davidic-sonship. If the Christ is only David's son (a political king in David's dynasty), Psalm 110 is inexplicable. There must be something more.</p>",
"42": "<p>'For David himself says in the Book of Psalms, The Lord said to my Lord, Sit at my right hand' — Ps 110:1 (ho Kyrios tō kyriō mou — 'the LORD said to my Lord') is the most quoted OT text in the NT, appearing in Acts 2:34-35; 1 Cor 15:25; Heb 1:13; 10:13. David's 'my Lord' (the second Kyrios) is a superior — David's lord, to whom YHWH speaks. David addressing the Christ as 'my Lord' establishes the Christ's supra-Davidic identity: he is the son of David by lineage but the Lord of David by nature. The genealogical relationship is real but insufficient to describe what the Christ is. The Davidic sonship is a category that contains but does not exhaust his identity.</p>",
"43": "<p>'Until I make your enemies your footstool' — the enthronement of the Christ at YHWH's right hand 'until his enemies become his footstool' is the Ascension-to-Parousia description in miniature. Christ is at the Father's right hand now (Acts 2:33-35 — Peter's Pentecost sermon citing this exact verse); his enemies are being subjected to him through the gospel now; his enemies will be finally and completely subjected at the Parousia (1 Cor 15:25 — 'he must reign until he has put all his enemies under his feet'). The 'until' is the present age; the footstool is the final subjugation of all that opposes the kingdom.</p>",
"44": "<p>'David thus calls him Lord, so how is he his son?' — the unanswerable question leaves the crowd (and the reader) with the puzzle that only the Incarnation resolves: the Christ is both David's son (in the flesh) and David's Lord (by nature). Rom 1:3-4 gives the fullest NT answer: 'descended from David according to the flesh and declared to be the Son of God in power according to the Spirit of holiness by his resurrection from the dead.' The Incarnation is the 'how' of the Psalm's seeming paradox: the Lord of David became the son of David without ceasing to be the Lord. The riddle's answer is the person of Jesus Christ.</p>",
"45": "<p>'And in the hearing of all the people he said to his disciples' — the shift from public controversy to semi-private teaching (directed to disciples, heard by all) is Luke's characteristic literary structure: Jesus teaches the disciples while the crowd overhears. The teaching that follows (about the scribes' behavior) is addressed to those who will need to distinguish authentic from performative religion in the coming age of the church. The disciples who have been watching the scribes question Christ must also be warned against adopting the scribes' patterns — the enemy without is also a temptation within.</p>",
"46": "<p>'Beware of the scribes, who like to walk around in long robes, and love greetings in the marketplaces and the best seats in the synagogues and the places of honor at feasts' — the scribes' performance of status (long robes = visible dignity; marketplace greetings = public honor; best synagogue seats = positional authority; honor at feasts = social priority) is the anti-pattern of the kingdom. The long robe that marks status is the opposite of the servant's apron (12:37 — the master puts on the servant's apron). The best seat is the opposite of the last place (14:10). The honor-at-feast is the opposite of the host who invites the poor (14:13). Christ's own life is the inversion of every scribal status-marker.</p>",
"47": "<p>'Who devour widows' houses and for a pretense make long prayers. They will receive the greater condemnation' — the indictment of the scribes moves from public performance to private exploitation: 'devouring widows' houses' is the abuse of legal guardianship over vulnerable women for financial gain. The long prayers are the religious cover for the exploitation — the performative piety that conceals practical predation. The 'greater condemnation' (perissoteron krima — a more severe judgment) falls on those who exploit the vulnerable under the cover of religious devotion: the higher the religious pretension, the greater the accountability. The widow who will give everything in the next verse (21:2) is the implicit contrast to the scribes who take everything from widows.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_CH19_20)
    save_comm('mkt-christ', 'luke', existing)
    ch19 = len(existing.get('19', {}))
    ch20 = len(existing.get('20', {}))
    print(f'Luke 19: {ch19}/48. Luke 20: {ch20}/47.')

if __name__ == '__main__':
    main()
